2042 |     // --- CORE UTILS ---
2043 |     /**
2044 |      * Tries to parse JSON. If it fails due to bad escaping (common with AI),
2045 |      * it attempts to double-escape backslashes that aren't valid JSON control chars.
2046 |      */
2047 |     function smartJSONParse(str) {
2048 |         if (!str) return null;
2049 |         let raw = str.trim();
2050 |         
2051 |         // 1. Extract only the JSON part (ignore AI chatter)
2052 |         const firstBracket = raw.indexOf('[');
2053 |         const lastBracket = raw.lastIndexOf(']');
2054 |         if (firstBracket !== -1 && lastBracket !== -1) {
2055 |             raw = raw.substring(firstBracket, lastBracket + 1);
2056 |         }
2057 | 
2058 |         // 2. Kill trailing commas in arrays/objects
2059 |         raw = raw.replace(/,[\s\r\n]*([\}\]])/g, '$1');
2060 | 
2061 |         // 3. Handle truncated JSON (AI cut off)
2062 |         let openBrackets = (raw.match(/\[/g) || []).length;
2063 |         let closeBrackets = (raw.match(/\]/g) || []).length;
2064 |         while (openBrackets > closeBrackets) { raw += ']'; closeBrackets++; }
2065 |         
2066 |         let openBraces = (raw.match(/\{/g) || []).length;
2067 |         let closeBraces = (raw.match(/\}/g) || []).length;
2068 |         while (openBraces > closeBraces) { raw += '}'; closeBraces++; }
2069 | 
2070 |         // 4. Structural String Sanitization
2071 |         let processed = '';
2072 |         let inString = false;
2073 |         let escapeNext = false;
2074 | 
2075 |         for (let i = 0; i < raw.length; i++) {
2076 |             let char = raw[i];
2077 |             if (char === '"' && !escapeNext) {
2078 |                 inString = !inString;
2079 |                 processed += char;
2080 |                 continue;
2081 |             }
2082 |             if (inString) {
2083 |                 if (char === '\\') {
2084 |                     const next = raw[i+1];
2085 |                     if (!['"', '\\', '/', 'b', 'f', 'n', 'r', 't', 'u'].includes(next)) processed += '\\\\';
2086 |                     else processed += char;
2087 |                 } else if (char === '\n' || char === '\r') {
2088 |                     processed += '\\n';
2089 |                 } else {
2090 |                     processed += char;
2091 |                 }
2092 |             } else {
2093 |                 processed += char;
2094 |             }
2095 |             escapeNext = (char === '\\' && !escapeNext);
2096 |         }
2097 | 
2098 |         try {
2099 |             return JSON.parse(processed);
2100 |         } catch (e) {
2101 |             console.warn("Necromancer fallback triggered");
2102 |             const desperate = processed
2103 |                 .replace(/\\"/g, '"').replace(/"/g, '\\"')
2104 |                 .replace(/\\"([a-z0-9_]+)\\":/gi, '"$1":')
2105 |                 .replace(/:[\s]*\\"([\s\S]*?)\\"[\s]*([,}\]])/g, ': "$1"$2');
2106 |             try { return JSON.parse(desperate); } catch (e3) { throw e; }
2107 |         }
2108 |     }
