2363 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2364 |     function applyLocalPatch(content, ops) {
2365 |         let lines = content.split('\n');
2366 |         let logs = [];
2367 |         let success = true;
2368 | 
2369 |         if (typeof ops === 'string') {
2370 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2371 |         }
2372 | 
2373 |         ops.forEach(op => {
2374 |             if (op.action === 'comment') return;
2375 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2376 |             
2377 |             if (op.action === 'replace_block') {
2378 |                 // Strategy 1: Exact String Match (Fastest)
2379 |                 const currentStr = lines.join('\n');
2380 |                 if (currentStr.includes(op.find_block)) {
2381 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2382 |                     logs.push('Exact match applied');
2383 |                     return;
2384 |                 }
2385 | 
2386 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2387 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2388 |                 if (searchLines.length === 0) return;
2389 | 
2390 |                 let matchStart = -1;
2391 |                 let matchEnd = -1;
2392 | 
2393 |                 // Scan file lines
2394 |                 for (let i = 0; i < lines.length; i++) {
2395 |                     // If first line matches (ignoring whitespace)
2396 |                     if (lines[i].trim() === searchLines[0]) {
2397 |                         // Check subsequent lines
2398 |                         let allMatch = true;
2399 |                         let fileOffset = 0;
2400 |                         let searchOffset = 1;
2401 |                         
2402 |                         while (searchOffset < searchLines.length) {
2403 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2404 |                             const nextFile = lines[i + fileOffset + 1].trim();
2405 |                             // Skip empty lines in file if they aren't in search block
2406 |                             if (nextFile === '') {
2407 |                                 fileOffset++;
2408 |                                 continue;
2409 |                             }
2410 |                             if (nextFile !== searchLines[searchOffset]) {
2411 |                                 allMatch = false;
2412 |                                 break;
2413 |                             }
2414 |                             fileOffset++;
2415 |                             searchOffset++;
2416 |                         }
2417 | 
2418 |                         if (allMatch) {
2419 |                             matchStart = i;
2420 |                             matchEnd = i + fileOffset;
2421 |                             break;
2422 |                         }
2423 |                     }
2424 |                 }
2425 | 
2426 |                 if (matchStart !== -1) {
2427 |                     // Replace the range of lines
2428 |                     const replacement = op.replace_with.split('\n');
2429 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2430 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2431 |                 } else {
2432 |                     success = false;
2433 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2434 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2435 |                 }
2436 |             }
2437 |         });
2438 |         return { content: lines.join('\n'), success, logs };
2439 |     }
