2443 |     async function runAutoFixLoop(name, code, errorList) {
2444 |         const status = document.getElementById('ef-status-msg');
2445 |         let currentCode = code;
2446 |         let currentErrors = errorList;
2447 | 
2448 |         // Fix one by one (recursive loop)
2449 |         async function fixNext(index) {
2450 |             if (index >= currentErrors.length) return true; // All initial errors processed
2451 | 
2452 |             const err = currentErrors[index];
2453 |             status.innerText = `ð§ Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
2454 |             status.style.color = "#eab308"; // Dev yellow
2455 | 
2456 |             try {
2457 |                 // 1. Get Patch from AI
2458 |                 const res = await fetch(CONFIG.funcUrl, { 
2459 |                     method: 'POST', 
2460 |                     headers: {'Content-Type': 'application/json'},
2461 |                     body: apiBody({ 
2462 |                         action: 'propose_syntax_fix', 
2463 |                         code: currentCode, 
2464 |                         error: err 
2465 |                     })
2466 |                 });
2467 |                 const data = await res.json();
2468 |                 const ops = data.operations;
2469 | 
2470 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2471 | 
2472 |                 // 2. Apply Patch Locally
2473 |                 const patchResult = applyLocalPatch(currentCode, ops);
2474 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2475 | 
2476 |                 currentCode = patchResult.content;
2477 |                 document.getElementById('ef-code').value = currentCode; // Update UI
2478 | 
2479 |                 // 3. Re-Validate
2480 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
2481 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
2482 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
2483 |                 });
2484 |                 const scanData = await scanRes.json();
2485 | 
2486 |                 if (scanData.valid) {
2487 |                     status.innerText = "â Syntax Fixed!";
2488 |                     return true;
2489 |                 } else {
2490 |                     // If errors remain, update list and Prompt user
2491 |                     currentErrors = scanData.errors;
2492 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2493 |                         // Recursively fix the *new* first error (since layout changed)
2494 |                         return await fixNext(0);
2495 |                     } else {
2496 |                         return false;
2497 |                     }
2498 |                 }
2499 | 
2500 |             } catch (e) {
2501 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2502 |                     return await fixNext(index);
2503 |                 } else {
2504 |                     return false;
2505 |                 }
2506 |             }
2507 |         }
2508 | 
2509 |         return await fixNext(0);
2510 |     }
