5360 |     function formatBytes(bytes) {
5361 |         if (!bytes) return '0 B';
5362 |         const k = 1024;
5363 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5364 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5365 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5366 |     }
