5368 |     function timeAgo(dateString) {
5369 |         const date = new Date(dateString);
5370 |         const now = new Date();
5371 |         const seconds = Math.floor((now - date) / 1000);
5372 |         if (seconds < 10) return 'just now';
5373 |         if (seconds < 60) return seconds + 's ago';
5374 |         const minutes = Math.floor(seconds / 60);
5375 |         if (minutes < 60) return minutes + 'm ago';
5376 |         const hours = Math.floor(minutes / 60);
5377 |         if (hours < 24) return hours + 'h ago';
5378 |         return date.toLocaleDateString();
5379 |     }
