5581 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5582 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5583 |         
5584 |         const navItems = document.querySelectorAll('.nav-item');
5585 |         switchTab(tabId, navItems[navIndex]);
5586 | 
5587 |         const scrollContainer = document.querySelector('.main-view');
5588 |         let retryCount = 0;
5589 |         const MAX_RETRIES = 5;
5590 | 
5591 |         const attemptNavigation = async () => {
5592 |             const element = document.querySelector(selector);
5593 |             
5594 |             if (element) {
5595 |                 console.log("[DeepJump] Element found. Scrolling...");
5596 |                 
5597 |                 // Wait for any tab transition animations
5598 |                 await new Promise(r => setTimeout(r, 300));
5599 | 
5600 |                 let offsetTop = 0;
5601 |                 let curr = element;
5602 |                 while (curr && curr !== scrollContainer) {
5603 |                     offsetTop += curr.offsetTop;
5604 |                     curr = curr.offsetParent;
5605 |                 }
5606 | 
5607 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5608 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5609 | 
5610 |                 // Visual Highlight
5611 |                 element.style.transition = 'all 0.5s ease';
5612 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5613 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5614 |                 setTimeout(() => {
5615 |                     element.style.backgroundColor = '';
5616 |                     element.style.boxShadow = '';
5617 |                 }, 3000);
5618 |                 
5619 |                 console.groupEnd();
5620 |                 return true;
5621 |             }
5622 | 
5623 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5624 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5625 |                 retryCount++;
5626 |                 showGlobalToast("ð Searching deeper...");
5627 |                 
5628 |                 await loadMoreFn(); 
5629 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5630 |                 return attemptNavigation();
5631 |             }
5632 | 
5633 |             console.error("[DeepJump] Failed: Element not found after retries.");
5634 |             showGlobalToast("Entry not found in recent history.", true);
5635 |             console.groupEnd();
5636 |             return false;
5637 |         };
5638 | 
5639 |         setTimeout(attemptNavigation, 100);
5640 |     }
