8095 |     function extractTableNames(sql) {
8096 |         if (!sql) return [];
8097 |         const tables = [];
8098 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
8099 |         
8100 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
8101 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
8102 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
8103 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
8104 | 
8105 |         let match;
8106 |         while ((match = fromRegex.exec(sql)) !== null) {
8107 |             const name = match[1];
8108 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8109 |                 tables.push(name);
8110 |             }
8111 |         }
8112 |         
8113 |         while ((match = metaRegex.exec(sql)) !== null) {
8114 |             const name = match[1];
8115 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8116 |                 tables.push(name);
8117 |             }
8118 |         }
8119 | 
8120 |         return tables;
8121 |     }
