8126 |         
8127 |         const tables = extractTableNames(resultObj.sql);
8128 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
8129 | 
8130 |         const headers = Object.keys(data[0]);
